package main

import (
	"fmt"
	"math"
)

// BIT represents a Binary Indexed Tree
type BIT struct {
	size  int
	tree  []int
}

// NewBIT creates a new Binary Indexed Tree
func NewBIT(size int) *BIT {
	return &BIT{
		size: size,
		tree: make([]int, size+1),
	}
}

// Update updates the value at the given index
func (b *BIT) Update(index, delta int) {
	for i := index; i <= b.size; i += i & -i {
		b.tree[i] += delta
	}
}

// RangeQuery returns the sum from [1, index]
func (b *BIT) RangeQuery(index int) int {
	sum := 0
	for i := index; i > 0; i -= i & -i {
		sum += b.tree[i]
	}
	return sum
}

// RangeQuery returns the sum from [l, r]
func (b *BIT) RangeQueryLR(l, r int) int {
	return b.RangeQuery(r) - b.RangeQuery(l-1)
}

// solve is the main function to solve the problem
func solve(nums []int64, queries [][]int64) []int64 {
	n := len(nums)
	maxK := 5
	maxDepth := 6 // Since the maximum possible popcount-depth for numbers up to 1e15 is small

	// Precompute popcount-depth for all possible values up to 1e15
	maxVal := int64(1e15)
	depthMap := make([]int, maxVal+1)
	for x := 0; x <= int(maxVal); x++ {
		p := int64(x)
		d := 0
		for p > 0 {
			p = popcount(p)
			d++
			if d > maxDepth {
				break
			}
		}
		depthMap[x] = d
	}

	// Initialize a Binary Indexed Tree (Fenwick Tree) for each possible depth (0 to 5)
	fenwickTrees := make([]*BIT, maxK+1)
	for k := 0; k <= maxK; k++ {
		fenwickTrees[k] = NewBIT(n)
	}

	// Populate the BITs with initial values
	for i := 0; i < n; i++ {
		depth := depthMap[int(nums[i])]
		fenwickTrees[depth].Update(i+1, 1)
	}

	answer := make([]int64, 0, len(queries))

	for _, query := range queries {
		if query[0] == 1 {
			l := int(query[1])
			r := int(query[2])
			k := int(query[3])
			count := fenwickTrees[k].RangeQueryLR(l+1, r+1)
			answer = append(answer, int64(count))
		} else {
			idx := int(query[1])
			val := int64(query[2])
			oldVal := nums[idx]
			oldDepth := depthMap[int(oldVal)]
			fenwickTrees[oldDepth].Update(idx+1, -1)

			nums[idx] = val
			newDepth := depthMap[int(val)]
			fenwickTrees[newDepth].Update(idx+1, 1)
		}
	}

	return answer
}

// popcount returns the number of 1 bits in the binary representation of x
func popcount(x int64) int64 {
	var count int64
	for x > 0 {
		count += x & 1
		x >>= 1
	}
	return count
