    tree []int
    size int
}

func NewBIT(size int) *BIT {
    return &BIT{
        tree: make([]int, size+2),
        size: size,
    }
}

func (b *BIT) update(index, delta int) {
    for ; index <= b.size; index += index & -index {
        b.tree[index] += delta
    }
}

func (b *BIT) rangeQuery(end, start int) int {
    return b.rangeSum(end) - b.rangeSum(start-1)
}

func (b *BIT) rangeSum(index int) int {
    res := 0
    for ; index > 0; index -= index & -index {
        res += b.tree[index]
    }
    return res
